<?php
declare(strict_types=1);

function sf_vp3_clip_source_path(array $clip):array{$key=sf_mp_safe_key((string)$clip['source_storage_key']);if($key==='')return['ok'=>false,'error'=>'invalid_source_storage_key'];if(($clip['source_driver']??'local')==='local'){$path=sf_mp_local_path($key);return['ok'=>is_string($path)&&is_file($path),'path'=>$path,'temporary'=>false,'error'=>'source_file_missing'];}if(!function_exists('sf_mp_s3_presign')||!function_exists('curl_init'))return['ok'=>false,'error'=>'s3_source_unavailable'];$url=sf_mp_s3_presign('GET',$key,900);$dir=sf_mp_staging_root().'/vp3-clips';if(!is_dir($dir))@mkdir($dir,0750,true);$tmp=$dir.'/'.sf_vp3_clip_uuid().'.source';$fh=fopen($tmp,'wb');$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_FILE=>$fh,CURLOPT_FOLLOWLOCATION=>false,CURLOPT_CONNECTTIMEOUT=>15,CURLOPT_TIMEOUT=>3600,CURLOPT_SSL_VERIFYPEER=>true,CURLOPT_SSL_VERIFYHOST=>2]);$ok=curl_exec($ch);$status=(int)curl_getinfo($ch,CURLINFO_RESPONSE_CODE);curl_close($ch);fclose($fh);if(!$ok||$status<200||$status>=300){@unlink($tmp);return['ok'=>false,'error'=>'s3_source_download_failed'];}return['ok'=>true,'path'=>$tmp,'temporary'=>true];}
function sf_vp3_clip_render(int $id):array{
 $pdo=sf_db();$clip=sf_vp3_clip_by_id($id);if(!$pdo||!$clip)return['ok'=>false,'error'=>'clip_not_found'];if(empty($clip['rights_confirmed']))return['ok'=>false,'error'=>'rights_confirmation_required'];$source=sf_vp3_clip_source_path($clip);if(empty($source['ok']))return$source;$ffmpeg=sf_mp_binary_path('ffmpeg');if($ffmpeg==='')return['ok'=>false,'error'=>'ffmpeg_unavailable'];$dir=sf_vp3_clip_output_root().'/'.$clip['clip_uuid'];if(!is_dir($dir)&&!mkdir($dir,0750,true)&&!is_dir($dir))return['ok'=>false,'error'=>'clip_output_directory_failed'];$video=$dir.'/clip.mp4';$poster=$dir.'/poster.jpg';$dimensions=['9:16'=>[1080,1920],'1:1'=>[1080,1080],'4:5'=>[1080,1350],'16:9'=>[1920,1080]];[$w,$h]=$dimensions[$clip['aspect_ratio']]??$dimensions['9:16'];$filter="scale={$w}:{$h}:force_original_aspect_ratio=increase,crop={$w}:{$h}";$pdo->prepare("UPDATE vp3_clips SET local_status='rendering',last_error=NULL WHERE id=?")->execute([$id]);$r=sf_mp_run_process([$ffmpeg,'-y','-v','error','-ss',(string)$clip['trim_start_seconds'],'-i',(string)$source['path'],'-t',(string)$clip['duration_seconds'],'-vf',$filter,'-c:v','libx264','-preset','medium','-profile:v','high','-pix_fmt','yuv420p','-crf','20','-c:a','aac','-b:a','160k','-ar','48000','-movflags','+faststart',$video],7200);if(!empty($source['temporary']))@unlink((string)$source['path']);if(empty($r['ok'])){$pdo->prepare("UPDATE vp3_clips SET local_status='failed',last_error=? WHERE id=?")->execute([substr((string)($r['stderr']??'render_failed'),0,1000),$id]);return['ok'=>false,'error'=>'clip_render_failed','detail'=>$r['stderr']??''];}$posterOffset=max(0,min((float)$clip['duration_seconds']-0.1,(float)$clip['poster_at_seconds']-(float)$clip['trim_start_seconds']));$p=sf_mp_run_process([$ffmpeg,'-y','-v','error','-ss',(string)$posterOffset,'-i',$video,'-frames:v','1','-q:v','2',$poster],600);if(empty($p['ok'])){$pdo->prepare("UPDATE vp3_clips SET local_status='failed',last_error=? WHERE id=?")->execute(['poster_generation_failed',$id]);return['ok'=>false,'error'=>'poster_generation_failed'];}$pdo->prepare("UPDATE vp3_clips SET rendered_video_path=?,rendered_poster_path=?,local_status='ready',last_error=NULL,source_updated_at=NOW(),updated_at=NOW() WHERE id=?")->execute([$video,$poster,$id]);sf_vp3_clip_event($id,null,'render','success',null,['video_bytes'=>filesize($video),'poster_bytes'=>filesize($poster)]);return['ok'=>true,'video'=>$video,'poster'=>$poster];}
function sf_vp3_clip_absolute_url(string $path,array $query=[]):string{$receipt=sf_license_receipt()?:[];$base=rtrim((string)($receipt['base_url']??getenv('SF_PUBLIC_BASE_URL')?:''),'/');if($base===''||strtolower((string)parse_url($base,PHP_URL_SCHEME))!=='https')throw new RuntimeException('The installed license receipt must contain the public HTTPS base URL.');return$base.'/'.ltrim($path,'/').($query?'?'.http_build_query($query):'');}
function sf_vp3_clip_public_url(array $clip,string $kind):string{return sf_vp3_clip_absolute_url('vp3-clip-media.php',['clip'=>$clip['clip_uuid'],'token'=>$clip['public_token'],'kind'=>$kind]);}
